 54→    static func phaseText(_ phase: NSEvent.Phase) -> String {
 55→        var parts: [String] = []
 56→        if phase.contains(.began) { parts.append("began") }
 57→        if phase.contains(.stationary) { parts.append("stationary") }
 58→        if phase.contains(.changed) { parts.append("changed") }
 59→        if phase.contains(.ended) { parts.append("ended") }
 60→        if phase.contains(.cancelled) { parts.append("cancelled") }
 61→        if phase.contains(.mayBegin) { parts.append("mayBegin") }
 62→        return parts.isEmpty ? "[]" : parts.joined(separator: "|")
 63→    }
 64→}
